ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?fullname ?jobrole ?industry WHERE {
  ?s a :Students .
  ?e a :Enrollments .
  ?e p:hasStudents ?s .
  ?c a :Courses .
  ?e p:hasCourses ?c .
  ?s p:name ?fullname .
  ?c p:JobRole ?jobrole .
  ?c p:Industry ?industry .
} }
  component: { SELECT ?fullname ?jobrole WHERE {
  ?s a :Students .
  ?e a :Enrollments .
  ?e p:hasStudents ?s .
  ?c a :Courses .
  ?e p:hasCourses ?c .
  ?s p:name ?fullname .
  ?c p:JobRole ?jobrole .
} }
  component_2: { SELECT ?fullname ?industry WHERE {
  ?s a :Students .
  ?e a :Enrollments .
  ?e p:hasStudents ?s .
  ?c a :Courses .
  ?e p:hasCourses ?c .
  ?s p:name ?fullname .
  ?c p:Industry ?industry .
} }
}
